namespace sv_188e860dd26a4372aa06a51aa89d796d.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = [];

    public IReadOnlyList<CartItem> Items => _items.AsReadOnly();

    public int TotalCount => _items.Sum(i => i.Quantity);

    public decimal TotalPrice => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(CartItem item)
    {
        var existing = _items.FirstOrDefault(i => i.Id == item.Id);
        if (existing is not null)
        {
            existing.Quantity += item.Quantity;
        }
        else
        {
            _items.Add(new CartItem
            {
                Id = item.Id,
                Name = item.Name,
                Price = item.Price,
                Quantity = item.Quantity
            });
        }
        OnChange?.Invoke();
    }

    public void Remove(int productId)
    {
        _items.RemoveAll(i => i.Id == productId);
        OnChange?.Invoke();
    }

    public void Clear()
    {
        _items.Clear();
        OnChange?.Invoke();
    }
}

@using sv_188e860dd26a4372aa06a51aa89d796d.Services
@inject CartState Cart
@implements IDisposable

<div class="nav-item px-3">
    <NavLink class="nav-link" href="cart">
        <span class="bi bi-cart-nav-menu" aria-hidden="true"></span> Cart
        @if (Cart.TotalCount > 0)
        {
            <span class="badge bg-danger rounded-pill ms-auto">@Cart.TotalCount</span>
        }
    </NavLink>
</div>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += HandleCartChanged;
    }

    private void HandleCartChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Cart.OnChange -= HandleCartChanged;
    }
}

@page "/products"
@rendermode InteractiveServer
@using sv_188e860dd26a4372aa06a51aa89d796d.Services
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary btn-sm"
                            @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, decimal Price);

    private readonly Product[] _products =
    [
        new(1, "Wireless Mouse", 29.99m),
        new(2, "Mechanical Keyboard", 89.99m),
        new(3, "USB-C Hub", 49.99m),
        new(4, "Monitor Stand", 39.99m),
        new(5, "Webcam HD", 59.99m),
        new(6, "Desk Lamp", 24.99m)
    ];

    private void AddToCart(Product product)
    {
        Cart.Add(new CartItem
        {
            Id = product.Id,
            Name = product.Name,
            Price = product.Price,
            Quantity = 1
        });
    }
}

@page "/cart"
@rendermode InteractiveServer
@using sv_188e860dd26a4372aa06a51aa89d796d.Services
@inject CartState Cart
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (!Cart.Items.Any())
{
    <p class="text-muted">Your cart is empty.</p>
    <a href="products" class="btn btn-primary">Browse Products</a>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-danger btn-sm"
                                @onclick="() => Cart.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <div class="d-flex justify-content-between align-items-center mt-3">
        <h4>Total: @Cart.TotalPrice.ToString("C")</h4>
        <button class="btn btn-outline-danger" @onclick="Cart.Clear">Clear Cart</button>
    </div>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += HandleCartChanged;
    }

    private void HandleCartChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Cart.OnChange -= HandleCartChanged;
    }
}

